const { chromium } = require('playwright');
(async () => {
  const browser = await chromium.launch({headless:true});
  const page = await browser.newPage();
  await page.goto('https://inmobiliariaiparralde.com/');
  const selects = await page.$$eval('select', els => els.map(e => ({name:e.name,id:e.id,placeholder:e.placeholder,outerHTML:e.outerHTML.slice(0,300)})));
  console.log('selects', selects);
  const inputs = await page.$$eval('input', els => els.map(e => ({name:e.name,id:e.id,type:e.type,outerHTML:e.outerHTML.slice(0,300)})));
  console.log('inputs', inputs);
  console.log('button text:', await page.$$eval('button', b=>b.map(x=>x.textContent.trim())));
  await browser.close();
})();
