const { chromium } = require('playwright');
(async () => {
  const browser = await chromium.launch({headless:true});
  const page = await browser.newPage();
  await page.goto('https://inmobiliariaiparralde.com/', {waitUntil:'networkidle'});
  console.log('url', page.url());
  const forms = await page.$$eval('form', fs => fs.map(f => ({id:f.id, name:f.name, action:f.action, method:f.method, innerHTML:f.innerHTML.slice(0,300)})));
  console.log('forms', forms.map((f,i)=>({...f, idx:i})).slice(0,7));
  const searchButtons = await page.$$eval('button,input[type=submit]', bs => bs.map(b => ({type:b.type, text:b.textContent?b.textContent.trim():b.value, id:b.id, class:b.className})).slice(0,30));
  console.log('searchButtons', searchButtons);
  await browser.close();
})();
