cd /home/sergio/Documentos/gaise/exercise1-gaise/ex1 && node <<'NODE'
const { chromium } = require('playwright');
(async () => {
  const browser = await chromium.launch({headless:true});
  const page = await browser.newPage();
  await page.goto('https://inmobiliariaiparralde.com/', {waitUntil:'networkidle'});
  await page.selectOption('form[action*="listado_de_inmuebles"] select[name="tipoInmueble[]"]', 'piso');
  await page.selectOption('form[action*="listado_de_inmuebles"] select[name="municipio[]"]', 'Hendaye');
  await Promise.all([
    page.waitForNavigation({waitUntil:'networkidle'}),
    page.click('form[action*="listado_de_inmuebles"] button[type="submit"]')
  ]);
  console.log('after search url', page.url());
  // inspect some listing wrappers
  const itemSelectors = await page.$$eval('article, .property, .item, .col-xs-12', elements => elements.slice(0,30).map(el => {
    const cls = el.className;
    const tag = el.tagName;
    const html = el.outerHTML.slice(0,350);
    return {tag,cls,html};
  }));
  console.log('items sample', itemSelectors.slice(0,12));
  // possible results count
  const total = await page.$$eval('a[href*="inmuebles/detalle"]', els => els.length);
  console.log('detail links count', total);
  await browser.close();
})();
