const { chromium } = require('playwright');
(async () => {
  const browser = await chromium.launch({headless:true});
  const page = await browser.newPage();

  await page.goto('https://inmobiliariaiparralde.com/', {waitUntil:'networkidle'});

  // Set the desired filters
  await page.selectOption('form[action*="listado_de_inmuebles"] select[name="tipoInmueble[]"]', 'piso');
  await page.selectOption('form[action*="listado_de_inmuebles"] select[name="municipio[]"]', 'Hendaye');

  await Promise.all([
    page.waitForNavigation({waitUntil:'networkidle'}),
    page.click('form[action*="listado_de_inmuebles"] button[type="submit"]')
  ]);

  // Helper to extract rows from current visible page
  const extractCurrent = await page.evaluate(() => {
    const rows = [];
    const now = new Date().toISOString();
    const items = Array.from(document.querySelectorAll('.item')).filter(item => item.offsetParent !== null || item.style.display !== 'none');
    for (const item of items) {
      const linkEl = item.querySelector('h4 a, .image a');
      const url = linkEl?.href?.trim() || null;
      const title = (item.querySelector('h4 a')?.textContent || item.querySelector('.image a img')?.alt || '').trim();
      const price = (item.querySelector('.nav_tag.price')?.textContent || '').trim().replace(/\s+/g, ' ');
      const location = (item.querySelector('p')?.textContent || '').trim().replace(/\s+/g, ' ');
      if (!url) continue;
      const idMatch = url.match(/(?:\/|=)(\d+)(?:\D*?$)/);
      const stableId = idMatch ? idMatch[1] : url;
      rows.push({ title, price, location, detailUrl: url, timestamp: now, stableId });
    }
    return rows;
  });

  let results = [...extractCurrent];

  const pageLinks = await page.$$('.easyPaginateNav a.page');
  if (pageLinks.length > 1) {
    for (let i = 0; i < pageLinks.length; i++) {
      const link = pageLinks[i];
      await link.click();
      await page.waitForTimeout(500);
      const pageRows = await page.evaluate(() => {
        const rows = [];
        const now = new Date().toISOString();
        const items = Array.from(document.querySelectorAll('.item')).filter(item => item.offsetParent !== null || item.style.display !== 'none');
        for (const item of items) {
          const linkEl = item.querySelector('h4 a, .image a');
          const url = linkEl?.href?.trim() || null;
          const title = (item.querySelector('h4 a')?.textContent || item.querySelector('.image a img')?.alt || '').trim();
          const price = (item.querySelector('.nav_tag.price')?.textContent || '').trim().replace(/\s+/g, ' ');
          const location = (item.querySelector('p')?.textContent || '').trim().replace(/\s+/g, ' ');
          if (!url) continue;
          const idMatch = url.match(/(?:\/|=)(\d+)(?:\D*?$)/);
          const stableId = idMatch ? idMatch[1] : url;
          rows.push({ title, price, location, detailUrl: url, timestamp: now, stableId });
        }
        return rows;
      });
      // avoid duplicates by stableId
      const existingIds = new Set(results.map(r => r.stableId));
      for (const r of pageRows) {
        if (!existingIds.has(r.stableId)) {
          results.push(r);
          existingIds.add(r.stableId);
        }
      }
    }
  }

  console.log(JSON.stringify(results, null, 2));
  await browser.close();
})();
